#include "sda_distribution.h"
#include <mpfr.h>
int sda_distribution_abs_gaussian(const sda_config*cfg,mpfr_t*probs,size_t n){ mpfr_prec_t pr=cfg->mpfr_precision; mpfr_t sum,tmp,x,s2,pi; mpfr_inits2(pr,sum,tmp,x,s2,pi,(mpfr_ptr)0); mpfr_const_pi(pi,MPFR_RNDN); mpfr_set_d(s2,cfg->sigma,MPFR_RNDN); mpfr_mul(s2,s2,s2,MPFR_RNDN); mpfr_set_zero(sum,0); for(size_t i=0;i<n;i++){ long val=cfg->support_min+(long)i; mpfr_set_si(x,val,MPFR_RNDN); mpfr_mul(x,x,x,MPFR_RNDN); mpfr_mul(x,x,pi,MPFR_RNDN); mpfr_div(x,x,s2,MPFR_RNDN); mpfr_neg(x,x,MPFR_RNDN); mpfr_exp(tmp,x,MPFR_RNDN); if(val>0) mpfr_mul_ui(tmp,tmp,2,MPFR_RNDN); mpfr_set(probs[i],tmp,MPFR_RNDN); mpfr_add(sum,sum,tmp,MPFR_RNDN);} for(size_t i=0;i<n;i++) mpfr_div(probs[i],probs[i],sum,MPFR_RNDN); mpfr_clears(sum,tmp,x,s2,pi,(mpfr_ptr)0); return 0; }
